   139	  int16x4_t al,ah,bl,bh,bfl,bfh; 
   140	  int32x2_t abr0l,abr0h,abr1l,abr1h,abi0l,abi0h,abi1l,abi1h;
   141	  al  = vget_low_s16(a);     ah = vget_high_s16(a);
   142	  bl  = vget_low_s16(b);     bh = vget_high_s16(b);
   143	  bfl = vget_low_s16(bflip); bfh = vget_high_s16(bflip);
   144	
   145	  ab_re0 = vmull_s16(al,bl);
   146	  ab_re1 = vmull_s16(ah,bh);
   147	  ab_im0 = vmull_s16(al,bfl);
   148	  ab_im1 = vmull_s16(ah,bfh);
   149	
   150	  abr0l = vget_low_s32(ab_re0); abr0h = vget_high_s32(ab_re0);
   151	  abr1l = vget_low_s32(ab_re1); abr1h = vget_high_s32(ab_re1);
   152	  abi0l = vget_low_s32(ab_im0); abi0h = vget_high_s32(ab_im0);
   153	  abi1l = vget_low_s32(ab_im1); abi1h = vget_high_s32(ab_im1);
   154	
   155	  *re32 = vcombine_s32(vpadd_s32(abr0l,abr0h),
   156			       vpadd_s32(abr1l,abr1h));
   157	  *im32 = vcombine_s32(vpadd_s32(abi0l,abi0h),
   158			       vpadd_s32(abi1l,abi1h));
